@startuml
left to right direction
skinparam packageStyle rectangle
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

class "Invoker" {
  <<C>>
}

class "Command" {
  <<I>>
  + execute()
}

class "ConcreteCommand" {
  <<C>>
}

class "Receiver" {
  <<C>>
  + action()
}

class "Client" {
  <<C>>
}

"Invoker" ..> "Command" : aggregation
"Command" <|-- "ConcreteCommand"
"ConcreteCommand" --> "Receiver"
"Client" ..> "ConcreteCommand"
"Client" --> "Receiver"

note left of "ConcreteCommand"
  Receiver -> action()
end note

@enduml
